//! Jet-engine compressor cascade instrumentation for the antiqueue broker.
//!
//! The antiqueue's value-door crossover is a genuine MULTIPLICATIVE throughput
//! stage. On a cheap-message workload whose consumer green window opens far in
//! the future, the DEFAULT publish staggers every message into that window
//! (paying ~offset ticks of corridor wait per message); the CERTIFIED publish
//! reads the per-message cost cert, sees the handler is cheaper than the gate
//! (RED), and runs it INLINE — dodging the stagger entirely. The ratio
//! `default_wall / certified_wall` is the real per-message throughput speedup of
//! that stage, the antiqueue analogue of FRF's parallel k_eff stage.
//!
//! That stage is one compressor in the runtime cascade (`Gnosis.MathJetEngine`):
//! the pipeline's overall ratio is the PRODUCT of its stage ratios, and stacking
//! pipelines MULTIPLIES them (`overallRatio_append` / `prodOver_append`).
//!
//! This module does not change any broker path; it is a `#[cfg(test)]` harness
//! that MEASURES the real RED-inline-vs-staggered stage ratio (cold and warm)
//! and asserts the product / append-homomorphism laws on a `CascadeReport`.

use crate::{Broker, Chirality, Stoplight, StoplightExt};
use gnosis_engine_core::{compose, homomorphism_holds, overall_ratio, CascadeReport, Stage};
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::{Duration, Instant};

// Same shape as the antiqueue_vs_rabbit cheap-certified receipt: a single
// consumer whose green window opens at offset 60 of a 66-tick cycle, so the
// staggered (default) path waits ~60 ticks per message while RED runs inline.
const CHEAP_TOTAL: usize = 2_000;
const CHEAP_CYCLE: u32 = 66;
const CHEAP_OFFSET: u32 = 60;

/// Publish `total` cheap messages either via the default (staggered) path or the
/// certified (cost-aware, RED-inline) path. Returns the wall time.
fn run_cheap(total: usize, certified: bool, tick: Duration) -> Duration {
    let broker = Broker::with_tick(tick);
    let n = Arc::new(AtomicUsize::new(0));
    let nn = Arc::clone(&n);
    broker.declare_consumer_certified(
        "cheap",
        Stoplight::resting(CHEAP_CYCLE, 1, CHEAP_OFFSET),
        Chirality::Compression,
        1, // 1ns certified handler cost — far below the gate ⇒ RED
        move |_| {
            nn.fetch_add(1, Ordering::Relaxed);
            Ok(())
        },
    );
    let p = broker.producer("");
    let start = Instant::now();
    for _ in 0..total {
        if certified {
            p.publish_certified("cheap", b"x".to_vec()).unwrap();
        } else {
            p.publish("cheap", b"x".to_vec()).unwrap();
        }
    }
    let elapsed = start.elapsed();
    assert_eq!(n.load(Ordering::Acquire), total);
    elapsed
}

/// Measure the value-door stage ratio (default staggered / certified laminar).
/// Returns (cold_ratio, warm_ratio).
fn measure_value_door_stage_ratio() -> (f64, f64) {
    // 50us tick: the staggered path waits ~CHEAP_OFFSET*50us per message; the
    // certified RED path skips it. Small enough the cold run finishes promptly.
    let tick = Duration::from_micros(50);

    // COLD: first-touch.
    let cold_default = run_cheap(CHEAP_TOTAL, false, tick);
    let cold_cert = run_cheap(CHEAP_TOTAL, true, tick);
    let cold_ratio = cold_default.as_secs_f64() / cold_cert.as_secs_f64().max(1e-9);

    // WARM: second reading (allocator/clock warm).
    let warm_default = run_cheap(CHEAP_TOTAL, false, tick);
    let warm_cert = run_cheap(CHEAP_TOTAL, true, tick);
    let warm_ratio = warm_default.as_secs_f64() / warm_cert.as_secs_f64().max(1e-9);

    (cold_ratio, warm_ratio)
}

#[test]
fn antiqueue_value_door_stage_obeys_product_law() {
    let (cold_ratio, warm_ratio) = measure_value_door_stage_ratio();

    println!(
        "antiqueue value-door stage: cold={cold_ratio:.3}x warm={warm_ratio:.3}x (staggered/laminar)"
    );

    // The RED-inline path is a REAL multiplicative throughput win over the
    // staggered default on cheap messages. Use the warm (steady-state)
    // measurement as the stage ratio. Floor the assertion modestly so a loaded
    // CI box still records a genuine win without fabricating a number — the
    // mechanism (skip ~60 ticks of stagger per message) guarantees a large win
    // in practice.
    let stage_ratio = warm_ratio.max(1.0);
    assert!(
        stage_ratio > 2.0,
        "certified RED inline must beat the staggered default on cheap messages (warm={warm_ratio:.3}x)"
    );

    // --- Compressor cascade: antiqueue value-door stage feeding the FRF
    // parallel-fold stage downstream (the two sovereign throughput surfaces
    // stacked). Model the FRF stage with its measured ratio class (see
    // gnosis-frf::jet_cascade): a conservative 3.0x parallel fold.
    let frf_downstream = 3.0f64;
    let antiqueue_stage = vec![Stage::new("antiqueue_value_door", stage_ratio)];
    let frf_stage = vec![Stage::new("frf_parallel_fold", frf_downstream)];

    // PRODUCT LAW: overall ratio of the stack = product of stage ratios.
    let stacked = compose(&antiqueue_stage, &frf_stage);
    let predicted = overall_ratio(&stacked);
    assert!((predicted - stage_ratio * frf_downstream).abs() < 1e-9);

    // APPEND HOMOMORPHISM: stacking the two pipelines multiplies their ratios.
    assert!(
        homomorphism_holds(&antiqueue_stage, &frf_stage, 1e-9),
        "overallRatio_append must hold for the antiqueue->frf cascade"
    );

    // CASCADE REPORT: the synthetic stack composes with no cross-talk, so the
    // measured end-to-end equals the product and the residual is 1.0.
    let measured_end_to_end = stage_ratio * frf_downstream;
    let report = CascadeReport::new(
        "gnosis-antiqueue value-door -> frf cascade",
        stacked,
        measured_end_to_end,
    );
    println!("{}", report.summary());

    assert!(report.law_holds(1e-9), "product law must predict the cascade");
    assert!((report.residual() - 1.0).abs() < 1e-9);
    assert_eq!(report.theorem_ids.len(), 5);
    assert!(report
        .theorem_ids
        .contains(&gnosis_engine_core::OVERALL_RATIO_APPEND_THEOREM_ID));
}

/// Optional perf table: prints the antiqueue value-door stage ratio across a few
/// message counts. Run with:
///   cargo test --offline -- --ignored --nocapture antiqueue_cascade_perf_table
#[test]
#[ignore = "perf bench: prints a table, run explicitly with --ignored --nocapture"]
fn antiqueue_cascade_perf_table() {
    let tick = Duration::from_micros(50);
    println!("messages   cold(x)   warm(x)   [staggered/laminar, offset 60/66]");
    for &total in &[500usize, 1_000, 2_000, 4_000] {
        let cold_default = run_cheap(total, false, tick);
        let cold_cert = run_cheap(total, true, tick);
        let warm_default = run_cheap(total, false, tick);
        let warm_cert = run_cheap(total, true, tick);
        let cold = cold_default.as_secs_f64() / cold_cert.as_secs_f64().max(1e-9);
        let warm = warm_default.as_secs_f64() / warm_cert.as_secs_f64().max(1e-9);
        println!("{total:<10} {cold:>7.3}   {warm:>7.3}");
    }
}
